#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char *s = (char*)malloc(N+2);
        scanf("%s",s);
        long long ans=0;
        for(int i=0;i<N;i++){
            if(s[i]==':'){
                int j=i+1;
                while(j<N && s[j]==')') j++;
                if(j>i+1 && j<N && s[j]==':') ans++;
            }
        }
        printf("%lld\n",ans);
        free(s);
    }
    return 0;
}

