import sys

def solve():
    data = sys.stdin.read().split()
    it = iter(data)
    t = int(next(it))
    out = []
    for _ in range(t):
        n = int(next(it))
        s = next(it)
        ans = 0
        i = 0
        while i < n:
            if s[i] == ':':
                j = i + 1
                while j < n and s[j] == ')':
                    j += 1
                if j > i + 1 and j < n and s[j] == ':':
                    ans += 1
            i += 1
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

